import React from "react";
import ReactDOM from "react-dom/client";
import "@/index.css";
import App from "@/App";

// Register the service worker for PWA install + offline shell. Only
// enable in production builds; dev mode gets HMR and the worker
// would just cause confusion.
if (process.env.NODE_ENV === "production" && "serviceWorker" in navigator) {
  window.addEventListener("load", () => {
    navigator.serviceWorker
      .register(`${process.env.PUBLIC_URL || ""}/sw.js`)
      .catch((err) => {
        // Service worker registration failures are non-fatal — the
        // app still works, just no offline shell and no install prompt.
        console.warn("[Castia] Service worker registration failed:", err);
      });
  });
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);
