// Cross-platform key labels. Detected once at module load — the OS
// doesn't change at runtime, so we don't need a hook.
const detectMac = () => {
  if (typeof navigator === "undefined") return false;
  if (navigator.userAgentData?.platform) {
    return /mac/i.test(navigator.userAgentData.platform);
  }
  const platform = navigator.platform || "";
  const ua = navigator.userAgent || "";
  return /Mac|iPhone|iPad|iPod/.test(platform) || /Mac OS X/.test(ua);
};

export const IS_MAC = detectMac();
export const CMD_KEY_LABEL = IS_MAC ? "⌘" : "Ctrl";
export const CMD_KEY_CHIP = IS_MAC ? "⌘" : "Ctrl";
