// ---------- shared atoms ----------

const ConfDot = ({ conf }) => {
  const map = {
    high: "bg-emerald-400", good: "bg-lime-400", fair: "bg-amber-400",
    low: "bg-orange-400", unreliable: "bg-zinc-600",
  };
  return <span className={`inline-block w-1.5 h-1.5 rounded-full ${map[conf] || "bg-zinc-600"}`}></span>;
};

const Trend = ({ trend }) => {
  if (trend === "up") return <span className="inline-flex items-center gap-1.5 text-emerald-400"><TrendingUp className="w-4 h-4" /> Rising</span>;
  if (trend === "down") return <span className="inline-flex items-center gap-1.5 text-red-400"><TrendingDown className="w-4 h-4" /> Falling</span>;
  return <span className="inline-flex items-center gap-1.5 text-zinc-400"><Minus className="w-4 h-4" /> Stable</span>;
};

// Display metadata for the export variant selector. Size string is
// the dimensions of the rendered PNG; label is the menu text.
const VARIANT_META = {
  item: { label: "Share card", size: "1200 × 630" },
  compact: { label: "Square (mobile)", size: "1080 × 1080" },
};

// Round to a "Castia-friendly" denomination that matches the price
// steps the auction house actually uses (e.g. 6250 → 6250, 8764 → 8750,
// 192310 → 190000, 4664000 → 4650000). Steps are picked by magnitude
// from the legacy castia-market reference: 50 below 10k, 500 from
// 10k-100k, 5k from 100k-1M, 50k above 1M.
function cleanRound(n) {
  const v = Math.abs(n);
  let step;
  if (v >= 1_000_000) step = 50_000;
  else if (v >= 100_000) step = 5_000;
  else if (v >= 10_000) step = 500;
  else step = 50;
  return Math.round(n / step) * step;
}

function CopyMedianButton({ value }) {
  const [copied, setCopied] = useState(false);
  if (!value || value <= 0) return null;
  const text = String(cleanRound(value));
  const onCopy = async () => {
    try {
      if (navigator.clipboard && window.isSecureContext) {
        await navigator.clipboard.writeText(text);
      } else {
        const ta = document.createElement("textarea");
        ta.value = text;
        ta.style.position = "fixed";
        ta.style.opacity = "0";
        document.body.appendChild(ta);
        ta.select();
        document.execCommand("copy");
        document.body.removeChild(ta);
      }
      setCopied(true);
      toast.success(`Copied ${text}`);
      setTimeout(() => setCopied(false), 1500);
    } catch {
      toast.error("Couldn't copy — try selecting manually");
    }
  };
  return (
    <button
      type="button"
      data-testid="drawer-copy-median"
      onClick={onCopy}
      title={`Copy ${text} to clipboard (rounded for readability)`}
      className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded border border-white/10 hover:border-emerald-500/40 hover:text-emerald-400 text-zinc-400 font-mono text-[10px] uppercase tracking-wider transition-colors"
    >
      {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
      {copied ? "Copied" : "Copy"}
    </button>
  );
}

// ---------- ItemDetailContent ----------
//
// The full item detail surface (sub-header + hero + sparkline +
// enchantments + price alert + listing trail) rendered the same way
// in both the right-side drawer and the /item/:key page. The only
// chrome difference is the close button: in drawer mode it's a
// floating X that calls onClose; in page mode it's hidden because
// the user has browser back + site nav.
//
// Props:
//   itemKey       - the parsed market key (e.g. "Mithril Essence|t1")
//   onOpenSeller  - called with the seller name when a trail seller or
//                   sparkline point is clicked. In drawer mode this
//                   sets ?sellerView=<name> on the current URL; in
//                   page mode the page does the same so the global
//                   DetailDrawer opens the seller overlay.
//   onClose       - optional close handler. When provided, an X
//                   button is rendered in the sub-header. When omitted
//                   (page mode), the X is hidden and the user is
//                   expected to navigate via the browser back button
//                   or the site header.

export default function ItemDetailContent({ itemKey, onOpenSeller, onClose }) {
  const { market, sellers } = useMarket();
  const favorites = useFavorites();
  const compare = useCompare();
  const isComparing = compare.has(itemKey);
  const alerts = useAlerts();
  const navigate = useNavigate();

  const item = useMemo(() => market?.rowsByKey.get(itemKey) || null, [market, itemKey]);
  const itemQuery = item ? workerQueryFromKey(item.key) : null;
  const { data: auc, loading: aucLoading, error: aucError, refetch: refetchAuc } = useItemAuctions(itemQuery);
  const isPage = !onClose;

  // Fetch chest shop data for the "Where to Buy" section (page mode only).
  const [shopRows, setShopRows] = useState([]);
  const [shopLoading, setShopLoading] = useState(false);
  useEffect(() => {
    if (!itemQuery) return;
    let cancelled = false;
    setShopLoading(true);
    fetchChestShops({ item: itemQuery })
      .then((data) => { if (!cancelled) setShopRows(Array.isArray(data) ? data : data?.rows || data?.shops || []); })
      .catch(() => {}) // silent — chest shop data is a bonus
      .finally(() => { if (!cancelled) setShopLoading(false); });
    return () => { cancelled = true; };
  }, [isPage, itemQuery]);

  // Pre-compute the share-card payload so export can render the canvas
  // without re-computing item/auction summaries during capture.
  const topSellers = useMemo(() => {
    if (!auc?.auctions) return [];
    const seen = new Set();
    const out = [];
    const sorted = [...auc.auctions].sort((a, b) => a.unitPrice - b.unitPrice);
    for (const a of sorted) {
      if (seen.has(a.seller)) continue;
      seen.add(a.seller);
      const meta = sellers?.find((s) => s.name === a.seller);
      out.push({
        name: a.seller,
        unitPrice: a.unitPrice,
        label: meta?.isBlacklisted ? "Flagged" : (meta?.accuracyLabel || "Neutral"),
      });
      if (out.length >= 3) break;
    }
    return out;
  }, [auc?.auctions, sellers]);

  const exportData = useMemo(() => item ? {
    name: item.name,
    tier: item.tier,
    modifiers: item.modifiers || [],
    category: item.category,
    median: item.median,
    trend: item.trend,
    samples: item.samples,
    confidence: item.confidence,
    series: auc?.series || [],
    topSellers,
    generatedAt: Date.now(),
  } : null, [item, auc?.series, topSellers]);

  const [exporting, setExporting] = useState(false);
  const [exportVariant, setExportVariant] = useState("item");

  const handleExport = async () => {
    if (!exportData || exporting) return;
    setExporting(true);
    try {
      const blob = await renderCastiaCardToBlob(exportData, { variant: exportVariant });
      const objectUrl = URL.createObjectURL(blob);
      const link = document.createElement("a");
      const safeKey = (itemKey || "item").replace(/[^a-z0-9]+/gi, "_").toLowerCase();
      const variantTag = exportVariant === "item" ? "" : `-${exportVariant}`;
      link.download = `castia${variantTag}-${safeKey}.png`;
      link.href = objectUrl;
      link.click();
      setTimeout(() => URL.revokeObjectURL(objectUrl), 1000);
      toast.success("Image saved", { description: `${link.download} downloaded` });
    } catch (e) {
      console.error("[export]", e);
      toast.error("Export failed", { description: e?.message || "Try again" });
    } finally {
      setExporting(false);
    }
  };

  // Alert draft
  const existingAlert = alerts.get(itemKey);
  const [alertOpen, setAlertOpen] = useState(false);
  const [alertKind, setAlertKind] = useState(existingAlert?.kind || "below");
  const [alertVal, setAlertVal] = useState(existingAlert?.value || "");
  useEffect(() => {
    setAlertKind(existingAlert?.kind || "below");
    setAlertVal(existingAlert ? String(existingAlert.value) : "");
    setAlertOpen(false);
  }, [itemKey]); // eslint-disable-line

  // Pull unique enchantments from the auction listing trail (when present)
  const enchantments = useMemo(() => {
    const merged = {};
    (auc?.auctions || []).forEach((a) => {
      Object.entries(a.enchantments || {}).forEach(([k, v]) => {
        if (!merged[k]) merged[k] = new Set();
        merged[k].add(v);
      });
    });
    return Object.entries(merged).map(([k, vs]) => ({ name: k, levels: Array.from(vs).sort() }));
  }, [auc]);

  const prefersReduced = useReducedMotion();
  useEffect(() => { if (itemKey) pushRecentlyViewed(itemKey); }, [itemKey]);

  if (!market) {
    return (
      <div className="flex items-center gap-2 text-zinc-500 font-mono text-sm p-10">
        <Loader2 className="w-4 h-4 animate-spin" /> Loading…
      </div>
    );
  }
  if (!item) {
    return (
      <div className="p-10 text-center">
        <div className="font-heading text-xl font-bold mb-2">Item not found</div>
        <p className="font-mono text-xs text-zinc-500">{itemKey}</p>
      </div>
    );
  }

  const isFav = favorites.has(itemKey);

  return (
    <div className="flex flex-col h-full">
      {/* Sticky header */}
      <div className="sticky top-0 z-10 bg-bg-base/95 backdrop-blur-xl border-b border-white/10 px-6 sm:px-8 py-4 flex items-center justify-between gap-3">
        <div className="flex items-center gap-2 flex-wrap min-w-0">
          {!onClose && (
            <button
              onClick={() => navigate(-1)}
              data-testid="item-detail-back"
              aria-label="Back"
              className="inline-flex items-center gap-1.5 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-2.5 py-1 rounded-sm transition-colors shrink-0"
            >
              <ArrowLeft className="w-3 h-3" /> Back
            </button>
          )}
          <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-emerald-400 px-2 py-0.5 border border-emerald-500/30 rounded-sm shrink-0">
            {item.category}
          </span>
          {item.tier > 0 && (
            <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-amber-400 px-2 py-0.5 border border-amber-500/30 rounded-sm shrink-0">
              T{item.tier}
            </span>
          )}
          <span className="shrink-0 max-[400px]:hidden">
            <FreshnessPill ms={item.lastSeenMs} prefix="Last sale" />
          </span>
        </div>
        <div className="flex items-center gap-1 shrink-0">
          {!isPage && (
            <Link
              to={`/item/${encodeURIComponent(itemKey)}`}
              data-testid="drawer-open-page"
              className="hidden sm:inline-flex items-center gap-1.5 border border-white/15 hover:border-emerald-500 hover:text-emerald-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-2.5 py-1.5 rounded-sm transition-colors"
            >
              Full page <ArrowUpRight className="w-3 h-3" />
            </Link>
          )}
          <button
            onClick={handleExport}
            disabled={exporting}
            data-testid="drawer-export"
            aria-label="Export as image"
            title={`Export as ${exportVariant === "compact" ? "1080x1080 square" : "1200x630 share card"}`}
            className="p-2 text-zinc-400 hover:text-emerald-400 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {exporting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
          </button>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <button
                data-testid="drawer-export-menu"
                aria-label="Export format"
                title="Choose export format"
                className="p-1 text-zinc-500 hover:text-emerald-400 transition-colors"
              >
                <ChevronDown className="w-3.5 h-3.5" />
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent
              align="end"
              className="w-56 bg-bg-base border border-white/10 rounded-sm shadow-xl z-50"
              data-testid="drawer-export-menu-list"
            >
              {EXPORT_VARIANTS.map((v) => {
                const meta = VARIANT_META[v];
                const active = exportVariant === v;
                return (
                  <DropdownMenuItem
                    key={v}
                    data-testid={`export-variant-${v}`}
                    onSelect={() => setExportVariant(v)}
                    className={`w-full text-left px-3 py-2 flex items-start gap-2 hover:bg-white/[0.06] transition-colors cursor-pointer focus:bg-white/[0.06] focus:text-inherit ${active ? "bg-emerald-500/10" : ""}`}
                  >
                    <div className="flex-1 min-w-0">
                      <div className={`font-mono text-[10px] uppercase tracking-wider ${active ? "text-emerald-300" : "text-white"}`}>{meta.label}</div>
                      <div className="font-mono text-[9px] text-zinc-500 mt-0.5">{meta.size}</div>
                    </div>
                    {active && <Check className="w-3.5 h-3.5 text-emerald-400 shrink-0 mt-0.5" />}
                  </DropdownMenuItem>
                );
              })}
            </DropdownMenuContent>
          </DropdownMenu>
          {onClose && (
            <button onClick={onClose} data-testid="drawer-close" aria-label="Close" className="p-2 text-zinc-400 hover:text-white transition-colors">
              <X className="w-5 h-5" />
            </button>
          )}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar">
        {/* Hero */}
        <div className="relative px-6 sm:px-8 pt-8 pb-6 overflow-hidden">
          <div className="absolute -top-32 -right-20 w-96 h-96 bg-emerald-500/15 blur-[100px] rounded-full pointer-events-none"></div>
          <div className="absolute inset-0 bg-grid opacity-30 [mask-image:radial-gradient(ellipse_at_top_right,_black_20%,_transparent_70%)] pointer-events-none"></div>

          {prefersReduced ? (
            <h2 className="relative font-heading text-3xl sm:text-5xl tracking-tighter font-black leading-[0.95]">
              <ItemName name={item.name} tier={item.tier} modifiers={item.modifiers} />
            </h2>
          ) : (
            <motion.h2
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              className="relative font-heading text-3xl sm:text-5xl tracking-tighter font-black leading-[0.95]"
            >
              <ItemName name={item.name} tier={item.tier} modifiers={item.modifiers} />
            </motion.h2>
          )}

          {prefersReduced ? (
            <div className="relative mt-6 flex items-end gap-4 flex-wrap">
              <PriceMorph
                value={item.median}
                className="font-heading text-3xl sm:text-4xl lg:text-6xl font-black tracking-tighter text-white leading-none"
              />
              <Trend trend={item.trend} />
            </div>
          ) : (
            <motion.div
              initial={{ opacity: 0, y: 14 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.05 }}
              className="relative mt-6 flex items-end gap-4 flex-wrap"
            >
            <PriceMorph
              value={item.median}
              className="font-heading text-3xl sm:text-4xl lg:text-6xl font-black tracking-tighter text-white leading-none"
            />
            <Trend trend={item.trend} />
          </motion.div>
          )}
          <div className="relative mt-2 font-mono text-xs text-zinc-500 tabular inline-flex items-center gap-2 flex-wrap">
            <span>median · {fmtFull(item.median)} coins</span>
            <CopyMedianButton value={item.median} />
          </div>

          {/* Actions */}
          <div className="relative mt-6 flex flex-wrap gap-2">
            <button
              data-testid="drawer-fav-btn"
              onClick={() => { favorites.toggle(itemKey); toast.success(isFav ? "Removed from favorites" : "Added to favorites"); }}
              className={`inline-flex items-center gap-2 px-4 py-2.5 rounded-sm border font-bold uppercase tracking-[0.18em] text-[11px] transition-all active:scale-95 ${
                isFav ? "bg-amber-500/10 border-amber-500 text-amber-400" : "border-white/15 hover:border-white/40 text-white"
              }`}
            >
              <Star className={`w-3.5 h-3.5 ${isFav ? "fill-amber-400" : ""}`} />
              {isFav ? "Favorited" : "Favorite"}
            </button>
            <button
              data-testid="drawer-compare-btn"
              onClick={() => {
                const res = compare.add(itemKey);
                if (res.full) toast.error(`Compare list is full (${compare.max} items)`);
                else toast.success(res.added ? "Added to Compare" : "Removed from Compare");
              }}
              className={`inline-flex items-center gap-2 px-4 py-2.5 rounded-sm border font-bold uppercase tracking-[0.18em] text-[11px] transition-all active:scale-95 ${
                isComparing ? "bg-indigo-500/10 border-indigo-500 text-indigo-400" : "border-white/15 hover:border-white/40 text-white"
              }`}
            >
              <GitCompare className="w-3.5 h-3.5" />
              {isComparing ? "Comparing" : "Compare"}
            </button>
            <button
              onClick={() => {
                navigator.clipboard.writeText(window.location.href);
                toast.success("Link copied");
              }}
              data-testid="copy-link-btn"
              className="inline-flex items-center gap-2 px-4 py-2.5 rounded-sm border border-white/15 hover:border-white/40 text-zinc-300 hover:text-white font-bold uppercase tracking-[0.18em] text-[11px] transition-all active:scale-95"
            >
              <Copy className="w-3.5 h-3.5" />
              Copy link
            </button>
          </div>
        </div>

        {/* Stat row */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-px bg-white/10 border-y border-white/10">
          {[
            { l: "IQR low", v: fmt(item.iqrLow) },
            { l: "IQR high", v: fmt(item.iqrHigh) },
            { l: "Conf.", v: <span className="inline-flex items-center gap-1.5"><ConfDot conf={item.confidence} /> <span className="text-sm">{item.confidence}</span></span> },
            { l: "Samples", v: item.samples },
          ].map((s, i) => (
            <div key={i} className="bg-bg-base px-3 sm:px-5 py-4">
              <div className="font-mono text-[9px] uppercase tracking-[0.25em] text-zinc-500 mb-1">{s.l}</div>
              <div className="font-heading text-lg sm:text-xl font-bold tabular">{s.v}</div>
            </div>
          ))}
        </div>

        {/* Sparkline / area chart */}
        <div className="px-6 sm:px-8 py-6">
          <div className="flex items-baseline justify-between mb-3 flex-wrap gap-2">
            <h3 className="font-heading text-lg font-bold">Price history</h3>
            {auc?.stats && (
              <div className="flex gap-3 font-mono text-[10px] uppercase tracking-wider text-zinc-500">
                <span>Low <span className="text-white tabular">{fmt(auc.stats.min)}</span></span>
                <span>Avg <span className="text-white tabular">{fmt(auc.stats.avg)}</span></span>
                <span>High <span className="text-white tabular">{fmt(auc.stats.max)}</span></span>
              </div>
            )}
          </div>
          <div className="relative w-full bg-white/[0.02] border border-white/10 rounded-xl p-3">
            {aucLoading ? (
              <div className="absolute inset-0 grid place-items-center text-zinc-500 font-mono text-xs" style={{ aspectRatio: "520 / 170" }}>
                <Loader2 className="w-4 h-4 animate-spin" />
              </div>
            ) : aucError ? (
              <div className="absolute inset-0 grid place-items-center text-zinc-500 font-mono text-[10px] uppercase tracking-wider text-center" style={{ aspectRatio: "520 / 170" }}>
                <div className="flex flex-col items-center gap-2">
                  <div className="flex items-center gap-1.5 text-amber-400">
                    <AlertTriangle className="w-3.5 h-3.5" /> Failed to load history
                  </div>
                  <div className="text-zinc-600 normal-case font-body text-[11px] max-w-[260px]">{aucError}</div>
                  <button
                    data-testid="drawer-chart-retry"
                    onClick={refetchAuc}
                    className="mt-1 inline-flex items-center gap-1.5 border border-white/15 hover:border-emerald-500/40 hover:text-emerald-400 text-white font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                  >
                    <RefreshCw className="w-3 h-3" /> Retry
                  </button>
                  <div className="text-zinc-700 normal-case font-body text-[10px] mt-1 max-w-[260px]">
                    Tip: if this keeps failing after a few retries, try reloading the page.
                  </div>
                </div>
              </div>
            ) : !auc?.series || auc.series.length === 0 ? (
              <div className="absolute inset-0 grid place-items-center text-zinc-500 font-mono text-[10px] uppercase tracking-wider" style={{ aspectRatio: "520 / 170" }}>
                No historical data yet
              </div>
            ) : (
              <div className="w-full" style={{ aspectRatio: "520 / 170" }}>
                <Sparkline
                  series={auc.series}
                  median={item.median}
                  gradientId="drawer-spark-fill"
                  compact
                  onPointClick={(point) => {
                    if (point?.seller && point.seller !== "—") {
                      onOpenSeller && onOpenSeller(point.seller);
                    }
                  }}
                  pointTooltip={({ point }) => {
                    if (!point) return null;
                    const when = point.ts ? new Date(point.ts).toLocaleString(undefined, {
                      month: "short", day: "numeric", hour: "2-digit", minute: "2-digit",
                    }) : "—";
                    return (
                      <div className="bg-bg-deep border border-white/20 rounded-md shadow-2xl px-3 py-2">
                      <div className="font-mono text-[9px] uppercase tracking-wider text-zinc-500 mb-1">
                        {when}
                      </div>
                      <div className="flex items-baseline gap-2 mb-1.5">
                        <span className="font-heading text-base font-bold text-white tabular">
                          {fmt(point.v)}
                        </span>
                        <span className="font-mono text-[9px] uppercase tracking-wider text-zinc-500">
                          per unit
                        </span>
                      </div>
                      <button
                        type="button"
                        onClick={(e) => {
                          e.stopPropagation();
                          if (point.seller && point.seller !== "—") {
                            onOpenSeller && onOpenSeller(point.seller);
                          }
                        }}
                        className="pointer-events-auto inline-flex items-center gap-1.5 max-w-full font-mono text-[10px] text-emerald-400 hover:text-emerald-300 transition-colors"
                      >
                        <span className="w-4 h-4 rounded bg-emerald-500/15 grid place-items-center text-[8px] font-bold text-emerald-300 shrink-0">
                          {String(point.seller || "?").slice(0, 1).toUpperCase()}
                        </span>
                        <span className="truncate">{point.seller || "Unknown seller"}</span>
                        <ArrowUpRight className="w-3 h-3 shrink-0" />
                      </button>
                      </div>
                    );
                  }}
                />
              </div>
            )}
          </div>
        </div>

        {/* Enchantments (from listing data) */}
        {enchantments.length > 0 && (
          <div className="px-6 sm:px-8 pb-4">
            <h3 className="font-heading text-lg font-bold mb-3 inline-flex items-center gap-2">
              <Sparkles className="w-4 h-4 text-amber-400" /> Enchantments seen
            </h3>
            <div className="flex flex-wrap gap-2">
              {enchantments.map((e) => (
                <span key={e.name} className="inline-flex items-center gap-1 bg-white/[0.03] border border-white/10 rounded-full px-3 py-1 text-xs">
                  <span className="text-white">{enchantmentLabel(e.name)}</span>
                  <span className="font-mono text-zinc-500 tabular">{e.levels.join(", ")}</span>
                </span>
              ))}
            </div>
          </div>
        )}

        {/* Price alert */}
        <div className="px-6 sm:px-8 pb-6">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-heading text-lg font-bold inline-flex items-center gap-2">
              {existingAlert
                ? <Bell className="w-4 h-4 text-emerald-400" />
                : <BellOff className="w-4 h-4 text-zinc-500" />}
              Price alert
            </h3>
            {existingAlert && !alertOpen && (
              <button onClick={() => setAlertOpen(true)} className="font-mono text-[10px] uppercase tracking-wider text-emerald-400 hover:text-emerald-300">Edit</button>
            )}
          </div>
          {existingAlert && !alertOpen ? (
            <div className="flex items-center justify-between bg-emerald-500/[0.06] border border-emerald-500/20 rounded-lg p-3">
              <div className="font-mono text-sm">
                Alert when median <span className="text-emerald-400">{existingAlert.kind === "below" ? "≤" : "≥"}</span> <span className="tabular text-white">{fmt(existingAlert.value)}</span>
              </div>
              <button
                onClick={() => { alerts.set(itemKey, null); toast.success("Alert removed"); }}
                className="font-mono text-[10px] uppercase tracking-wider text-zinc-400 hover:text-red-400 transition-colors"
              >
                Remove
              </button>
            </div>
          ) : (
            <div className="bg-white/[0.02] border border-white/10 rounded-lg p-3 flex gap-2 items-center flex-wrap">
              <select
                value={alertKind}
                onChange={(e) => setAlertKind(e.target.value)}
                aria-label="Alert condition"
                className="bg-bg-base border border-white/10 rounded px-2 py-1.5 text-xs font-mono uppercase tracking-wider text-white outline-none cursor-pointer"
              >
                <option value="below">Drops below</option>
                <option value="above">Rises above</option>
              </select>
              <input
                type="text"
                inputMode="numeric"
                pattern="[0-9]*"
                aria-label="Alert price threshold"
                value={alertVal}
                onChange={(e) => {
                  const cleaned = e.target.value.replace(/[^0-9.]/g, "").replace(/(\..*)\./g, "$1");
                  setAlertVal(cleaned);
                }}
                placeholder="e.g. 50000000"
                className="bg-bg-base border border-white/10 focus:border-emerald-500 rounded px-3 py-1.5 text-sm font-mono tabular text-white placeholder-zinc-600 outline-none w-44 max-w-full transition-colors"
              />
              <button
                data-testid="drawer-alert-save"
                onClick={() => {
                  const v = parseFloat(alertVal);
                  if (!v || v <= 0) { toast.error("Enter a valid amount"); return; }
                  alerts.set(itemKey, { kind: alertKind, value: v });
                  setAlertOpen(false);
                  toast.success(`Alert set: ${alertKind === "below" ? "≤" : "≥"} ${fmt(v)}`);
                }}
                className="inline-flex items-center gap-1.5 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm"
              >
                Save alert
              </button>
            </div>
          )}
        </div>

        {/* Listing trail */}
        <div className="px-6 sm:px-8 pb-10">
          <h3 className="font-heading text-lg font-bold mb-3">
            Listing trail
            {auc && <span className="ml-2 font-mono text-[10px] uppercase tracking-wider text-zinc-500">{auc.auctions.length} listings</span>}
          </h3>
          <div className="bg-bg-deeper border border-white/10 rounded-xl overflow-hidden">
            {aucLoading ? (
              <div className="p-6 text-center font-mono text-xs text-zinc-500">Loading…</div>
            ) : aucError ? (
              <div className="p-6 text-center flex flex-col items-center gap-2">
                <div className="font-mono text-[10px] uppercase tracking-wider text-amber-400 inline-flex items-center gap-1.5">
                  <AlertTriangle className="w-3.5 h-3.5" /> Failed to load listings
                </div>
                <div className="font-mono text-[10px] text-zinc-600 normal-case font-body">{aucError}</div>
                <button
                  data-testid="drawer-trail-retry"
                  onClick={refetchAuc}
                  className="inline-flex items-center gap-1.5 border border-white/15 hover:border-emerald-500/40 hover:text-emerald-400 text-white font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                >
                  <RefreshCw className="w-3 h-3" /> Retry
                </button>
                <div className="font-body text-[10px] text-zinc-700 mt-1 max-w-[320px]">
                  Tip: if this keeps failing after a few retries, try reloading the page.
                </div>
              </div>
            ) : !auc?.auctions.length ? (
              <div className="p-6 text-center font-mono text-[10px] uppercase tracking-wider text-zinc-500">No listings recorded</div>
            ) : (
              <ul className="divide-y divide-white/5">
                {auc.auctions.map((a, i) => {
                  const vsMedian = ((a.unitPrice - item.median) / item.median) * 100;
                  const cls = vsMedian > 5 ? "text-red-400" : vsMedian < -5 ? "text-emerald-400" : "text-white";
                  return (
                    <li key={i} className="px-4 py-3 flex items-center gap-3 hover:bg-white/[0.03] transition-colors">
                      <button
                        onClick={() => onOpenSeller && onOpenSeller(a.seller)}
                        data-testid={`drawer-trail-seller-${i}`}
                        className="flex items-center gap-2.5 min-w-0 flex-1 group/seller"
                      >
                        <img
                          src={`https://render.crafty.gg/3d/bust/${encodeURIComponent(a.seller)}`}
                          alt=""
                          width={28}
                          height={28}
                          className="rounded-sm bg-white/[0.04] shrink-0"
                          onError={(e) => { e.currentTarget.style.visibility = "hidden"; }}
                          loading="lazy"
                        />
                        <div className="text-left min-w-0">
                          <div className="text-sm font-medium text-white group-hover/seller:text-emerald-400 transition-colors truncate">{a.seller}</div>
                          <div className="font-mono text-[10px] text-zinc-500">
                            {a.timestamp ? new Date(a.timestamp).toLocaleString(undefined,{month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"}) : "—"}
                          </div>
                        </div>
                      </button>
                      <div className="text-right shrink-0">
                        <div className={`font-mono tabular ${cls}`}>{fmt(a.unitPrice)}</div>
                        <div className="font-mono text-[10px] text-zinc-500 tabular">
                          {vsMedian >= 0 ? "+" : ""}{vsMedian.toFixed(1)}% · ×{a.count}
                        </div>
                      </div>
                    </li>
                  );
                })}
              </ul>
            )}
          </div>
        </div>

        {/* Where to Buy */}
        <div className="px-6 sm:px-8 pb-10">
          <h3 className="font-heading text-lg font-bold mb-3">
            Where to Buy
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Auction House */}
            <div className="bg-bg-deeper border border-white/10 rounded-xl p-4">
              <div className="font-mono text-[10px] uppercase tracking-[0.2em] text-amber-400 mb-3 inline-flex items-center gap-1.5">
                Auction House
              </div>
              {aucLoading ? (
                <div className="text-xs text-zinc-500">Loading…</div>
              ) : !auc?.auctions?.length ? (
                <div className="text-xs text-zinc-600">No auction listings found.</div>
              ) : (
                <ul className="divide-y divide-white/5">
                  {auc.auctions.slice(0, 5).map((a, i) => {
                    const vsMedian = ((a.unitPrice - item.median) / item.median) * 100;
                    return (
                      <li key={i} className="py-2 flex items-center justify-between text-xs">
                        <span className="text-zinc-300 truncate mr-2">{a.seller}</span>
                        <span className="font-mono tabular text-white shrink-0">
                          {fmt(a.unitPrice)}
                          <span className="text-zinc-500 ml-1">
                            ({vsMedian >= 0 ? "+" : ""}{vsMedian.toFixed(1)}%)
                          </span>
                        </span>
                      </li>
                    );
                  })}
                </ul>
              )}
            </div>

            {/* Chest Shops */}
            <div className="bg-bg-deeper border border-white/10 rounded-xl p-4">
              <div className="font-mono text-[10px] uppercase tracking-[0.2em] text-indigo-400 mb-3 inline-flex items-center gap-1.5">
                Chest Shops
              </div>
              {shopLoading ? (
                <div className="text-xs text-zinc-500">Loading…</div>
              ) : shopRows.length === 0 ? (
                <div className="text-xs text-zinc-600">No chest shop listings found.</div>
              ) : (
                <ul className="divide-y divide-white/5">
                  {shopRows.slice(0, 5).map((r, i) => (
                    <li key={i} className="py-2 flex items-center justify-between text-xs">
                      <div className="min-w-0 flex-1 mr-2">
                        <div className="text-zinc-300 truncate">{r.seller || "\u2014"}</div>
                        {r.x != null && r.y != null && r.z != null && (
                          <div className="text-zinc-600 font-mono text-[10px] mt-0.5">
                            {r.dimensionKey?.replace(/_/g, " ") || ""} ({r.x}, {r.y}, {r.z})
                          </div>
                        )}
                      </div>
                      <span className="font-mono tabular text-white shrink-0">
                        {r.unitPrice > 0 ? fmt(r.unitPrice) : "\u2014"}
                      </span>
                    </li>
                  ))}
                </ul>
              )}
              {shopRows.length > 5 && (
                <Link
                  to={`/shops?item=${encodeURIComponent(itemQuery)}`}
                  className="mt-3 inline-flex items-center gap-1 text-[10px] font-mono uppercase tracking-wider text-indigo-400 hover:text-indigo-300 transition-colors"
                >
                  View all {shopRows.length} shops <ArrowUpRight className="w-3 h-3" />
                </Link>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
